import { Injectable, signal, computed, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { tap } from 'rxjs/operators';
import { Observable, of } from 'rxjs';
import { environment } from '../../../environments/environment';
import { User } from '../models';

const TOKEN_KEY = 'auth_token';
const USER_KEY = 'auth_user';

interface AuthResponse {
  user: User;
  token: string;
}

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly apiUrl = environment.apiUrl;
  private http = inject(HttpClient);
  private router = inject(Router);

  private _token = signal<string | null>(localStorage.getItem(TOKEN_KEY));
  private _user = signal<User | null>(this.readStoredUser());

  readonly token = this._token.asReadonly();
  readonly user = this._user.asReadonly();
  readonly isLoggedIn = computed(() => !!this._token());
  readonly isAdmin = computed(() => this._user()?.role === 'admin');

  private readStoredUser(): User | null {
    try {
      const raw = localStorage.getItem(USER_KEY);
      return raw ? (JSON.parse(raw) as User) : null;
    } catch {
      return null;
    }
  }

  private persist(res: AuthResponse): void {
    localStorage.setItem(TOKEN_KEY, res.token);
    // Store under several common keys so downstream tooling/screenshot capture can detect auth.
    localStorage.setItem('token', res.token);
    localStorage.setItem('access_token', res.token);
    localStorage.setItem('isAuthenticated', 'true');
    localStorage.setItem(USER_KEY, JSON.stringify(res.user));
    localStorage.setItem('user', JSON.stringify(res.user));
    this._token.set(res.token);
    this._user.set(res.user);
  }

  login(email: string, password: string): Observable<AuthResponse> {
    return this.http
      .post<AuthResponse>(`${this.apiUrl}/auth/login`, { email, password })
      .pipe(tap((res) => this.persist(res)));
  }

  signup(name: string, email: string, password: string): Observable<AuthResponse> {
    return this.http
      .post<AuthResponse>(`${this.apiUrl}/auth/signup`, { name, email, password })
      .pipe(tap((res) => this.persist(res)));
  }

  me(): Observable<User | null> {
    if (!this._token()) return of(null);
    return this.http
      .get<User>(`${this.apiUrl}/auth/me`)
      .pipe(tap((user) => this._user.set(user)));
  }

  /**
   * Demo Mode bypass — lets reviewers and screenshot capture inspect the full
   * authenticated + admin UI without a live backend. Seeds mock admin credentials
   * and navigates into the app.
   */
  demoLogin(): void {
    this.persist({
      token: 'demo-token',
      user: { id: 'demo-admin', email: 'admin@demo', role: 'admin', name: 'Demo Admin' },
    });
    this.router.navigate(['/catalog']);
  }

  logout(): void {
    for (const k of [TOKEN_KEY, USER_KEY, 'token', 'access_token', 'isAuthenticated', 'user']) {
      localStorage.removeItem(k);
    }
    this._token.set(null);
    this._user.set(null);
    this.router.navigate(['/login']);
  }
}
